ALTER TABLE time_management_methods
ADD COLUMN IF NOT EXISTS method_group TEXT NOT NULL DEFAULT 'не задана';

ALTER TABLE time_management_methods
ADD COLUMN IF NOT EXISTS role TEXT NOT NULL DEFAULT 'кандидат для выбора одного метода';

INSERT INTO time_management_methods (code, name, description, best_for, method_group, role)
VALUES
    ('smart', 'SMART', 'Формулирует цель через конкретность, измеримость, достижимость, релевантность и срок.', 'Задачи, где нужно сначала уточнить ожидаемый результат.', 'формулировка цели', 'уточняет измеримую цель'),
    ('smarter', 'SMARTER', 'Расширяет SMART за счет оценки результата и последующей корректировки цели.', 'Цели, которые нужно не только поставить, но и регулярно пересматривать.', 'формулировка цели', 'уточняет и пересматривает цель'),
    ('clear', 'CLEAR', 'Помогает ставить гибкие цели с учетом сотрудничества, ограничений и возможности корректировки.', 'Задачи с изменяющимися условиями и участием других людей.', 'формулировка цели', 'делает цель гибкой'),
    ('woop', 'WOOP', 'Связывает желание, результат, препятствие и план преодоления препятствия.', 'Личные цели, где важны мотивация и препятствия.', 'формулировка цели', 'связывает цель с препятствиями'),
    ('personal_okr', 'Personal OKR', 'Разделяет личную цель на измеримые ключевые результаты.', 'Долгосрочные личные цели с несколькими результатами.', 'формулировка цели', 'задает цель и ключевые результаты'),

    ('eisenhower', 'Eisenhower Matrix', 'Разделяет задачи по срочности и важности.', 'Ситуации с конкурирующими срочными и важными делами.', 'приоритизация', 'выбирает важное и срочное'),
    ('abcde', 'ABCDE', 'Присваивает задачам уровни важности от A до E.', 'Список задач, который нужно быстро упорядочить по важности.', 'приоритизация', 'ранжирует задачи по важности'),
    ('moscow', 'MoSCoW', 'Делит задачи на must, should, could и will not.', 'Планирование объема работы при ограниченном времени.', 'приоритизация', 'отделяет обязательное от желательного'),
    ('pareto_80_20', 'Pareto 80/20', 'Ищет небольшую часть действий, которая дает основной результат.', 'Задачи, где нужно сфокусироваться на главном эффекте.', 'приоритизация', 'находит действия с максимальной отдачей'),
    ('ivy_lee', 'Ivy Lee Method', 'Ограничивает день несколькими главными задачами в строгом порядке.', 'Планирование дня без перегрузки длинным списком дел.', 'приоритизация', 'выбирает главные задачи дня'),

    ('wbs', 'WBS', 'Разбивает крупную работу на управляемые части и результаты.', 'Большие задачи с несколькими понятными компонентами.', 'декомпозиция', 'разбивает работу на части'),
    ('backward_planning', 'Backward Planning', 'Строит план от конечного результата назад к первому действию.', 'Задачи с четким дедлайном и понятным финальным результатом.', 'декомпозиция', 'строит план от результата назад'),
    ('critical_path', 'Critical Path Method', 'Выделяет цепочку зависимых действий, определяющих общий срок.', 'Проекты, где важны зависимости между этапами.', 'декомпозиция', 'находит критическую цепочку'),
    ('one_three_five', '1-3-5 Rule', 'Планирует один крупный, три средних и пять малых шагов.', 'Дневное планирование с задачами разного размера.', 'декомпозиция', 'балансирует крупные и малые шаги'),
    ('alpen', 'ALPEN', 'Собирает задачи, оценивает длительность, резервирует буфер и проверяет план.', 'Планирование рабочего дня с учетом реального времени.', 'декомпозиция', 'строит реалистичный план дня'),

    ('time_blocking', 'Time Blocking', 'Выделяет фиксированные временные блоки под этапы работы.', 'Крупные задачи, которым нужно заранее выделить время.', 'распределение времени', 'распределяет работу по календарю'),
    ('timeboxing', 'Timeboxing', 'Ограничивает задачу заранее заданным временным контейнером.', 'Задачи, которые легко растягиваются без ограничения времени.', 'распределение времени', 'ограничивает время выполнения'),
    ('pomodoro', 'Pomodoro', 'Организует работу короткими фокус-сессиями с перерывами.', 'Задачи, требующие концентрации и устойчивого темпа.', 'распределение времени', 'задает ритм фокус-сессий'),
    ('flowtime', 'Flowtime', 'Позволяет работать непрерывно до естественной паузы и затем фиксировать отдых.', 'Творческие задачи, где важно не прерывать поток.', 'распределение времени', 'поддерживает естественный рабочий поток'),
    ('biological_prime_time', 'Biological Prime Time', 'Планирует сложные задачи на периоды максимальной личной энергии.', 'Задачи, требующие высокой умственной отдачи.', 'распределение времени', 'подбирает время по уровню энергии'),

    ('eat_that_frog', 'Eat That Frog', 'Предлагает начинать с самой неприятной или важной задачи.', 'Прокрастинируемые задачи с высоким эффектом.', 'старт / борьба с прокрастинацией', 'помогает начать с трудного'),
    ('two_minute_rule', 'Two-Minute Rule', 'Предлагает сразу выполнить действие, если оно занимает меньше двух минут.', 'Мелкие действия, которые не стоит откладывать.', 'старт / борьба с прокрастинацией', 'убирает мелкие задержки'),
    ('five_minute_rule', 'Five-Minute Rule', 'Снижает сопротивление через обещание поработать всего пять минут.', 'Задачи, к которым трудно приступить.', 'старт / борьба с прокрастинацией', 'снижает порог старта'),
    ('swiss_cheese', 'Swiss Cheese Method', 'Предлагает делать маленькие отверстия в большой задаче короткими подходами.', 'Большие задачи, вызывающие сопротивление.', 'старт / борьба с прокрастинацией', 'начинает большую задачу малыми действиями'),
    ('if_then_planning', 'If-Then Planning', 'Связывает условие и действие в формате если-то.', 'Задачи, где нужно заранее обойти типичные препятствия.', 'старт / борьба с прокрастинацией', 'готовит реакцию на препятствия'),

    ('gtd', 'Getting Things Done', 'Проясняет результат, следующие действия и систему контроля задач.', 'Неясные или перегруженные списки задач.', 'организация потока задач', 'организует поток входящих задач'),
    ('personal_kanban', 'Personal Kanban', 'Визуализирует задачи по стадиям и ограничивает количество работы в процессе.', 'Поток задач, где важно видеть статус и не перегружаться.', 'организация потока задач', 'визуализирует поток работы'),
    ('inbox_zero', 'Inbox Zero', 'Помогает регулярно очищать входящие сообщения и превращать их в действия.', 'Почта и входящие запросы, которые быстро накапливаются.', 'организация потока задач', 'управляет входящими сообщениями'),
    ('bullet_journal', 'Bullet Journal', 'Объединяет быстрые записи, задачи, события и миграцию незавершенного.', 'Личное планирование, где нужен простой бумажный или цифровой журнал.', 'организация потока задач', 'ведет личный журнал задач'),
    ('autofocus', 'Autofocus', 'Позволяет выбирать следующую задачу из списка по вниманию и готовности.', 'Гибкий список задач без жесткого расписания.', 'организация потока задач', 'выбирает следующую задачу по готовности'),

    ('single_tasking', 'Single-Tasking', 'Фокусирует внимание на одной задаче без параллельного переключения.', 'Работа, где ошибки возникают из-за многозадачности.', 'выполнение', 'удерживает фокус на одном действии'),
    ('task_batching', 'Task Batching', 'Группирует похожие задачи и выполняет их одним блоком.', 'Много однотипных мелких действий.', 'выполнение', 'объединяет похожие действия'),
    ('dont_break_chain', 'Don''t Break the Chain', 'Поддерживает регулярность через непрерывную цепочку выполненных дней.', 'Привычки и повторяющиеся личные цели.', 'выполнение', 'поддерживает регулярное выполнение'),
    ('ultradian_rhythm', 'Ultradian Rhythm Work Cycles', 'Строит работу длинными циклами с восстановительными паузами.', 'Интенсивная умственная работа на несколько часов.', 'выполнение', 'чередует глубокую работу и восстановление'),
    ('personal_sprint', 'Personal Sprint', 'Организует короткий личный спринт с целью, задачами и обзором результата.', 'Небольшой проект на несколько дней или неделю.', 'выполнение', 'ведет короткий личный спринт'),

    ('daily_review', 'Daily Review', 'Подводит итоги дня, обновляет задачи и выбирает следующий фокус.', 'Ежедневный контроль прогресса и планирование следующего дня.', 'контроль / завершение', 'проверяет прогресс за день'),
    ('weekly_review', 'Weekly Review', 'Пересматривает задачи, цели и календарь за неделю.', 'Поддержание порядка в задачах и целях на горизонте недели.', 'контроль / завершение', 'обновляет недельный план'),
    ('checklist', 'Checklist Method', 'Использует список проверок, чтобы не пропустить обязательные действия.', 'Повторяемые задачи и финальная проверка результата.', 'контроль / завершение', 'проверяет обязательные пункты'),
    ('action_priority_matrix', 'Action Priority Matrix', 'Сравнивает действия по усилию и эффекту.', 'Выбор задач, где важно учесть отдачу и затраты.', 'контроль / завершение', 'сравнивает усилие и эффект'),
    ('pickle_jar', 'Pickle Jar Theory', 'Помогает распределить время между крупными, средними и мелкими делами.', 'Планирование дня с задачами разного масштаба.', 'контроль / завершение', 'балансирует крупные и мелкие дела')
ON CONFLICT (code) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description,
    best_for = EXCLUDED.best_for,
    method_group = EXCLUDED.method_group,
    role = EXCLUDED.role;

INSERT INTO plan_templates (method_id, name, template)
SELECT
    m.id,
    'Базовый универсальный шаблон',
    jsonb_build_object(
        'method_code', m.code,
        'steps', jsonb_build_array(
            jsonb_build_object('title', 'Уточнить результат', 'description', 'Определить, какой результат должен быть получен по задаче "{task_title}".'),
            jsonb_build_object('title', 'Разбить работу на этапы', 'description', 'Выделить основные части задачи и порядок их выполнения.'),
            jsonb_build_object('title', 'Выполнить основной этап', 'description', 'Сделать действие, которое сильнее всего продвигает задачу к результату.'),
            jsonb_build_object('title', 'Проверить промежуточный результат', 'description', 'Сверить выполненную работу с целью и ограничениями.'),
            jsonb_build_object('title', 'Завершить и зафиксировать итог', 'description', 'Проверить финальный результат и отметить оставшиеся действия.')
        ),
        'schedule_hint', 'Запланировать задачу "{task_title}" по этапам и оставить {review_minutes} минут на проверку.'
    )
FROM time_management_methods m
WHERE NOT EXISTS (
    SELECT 1
    FROM plan_templates p
    WHERE p.method_id = m.id
);
